import re, json
from dataclasses import dataclass

@dataclass
class DeterministicResult:
    check: str
    passed: bool
    detail: str = ""

def check_json_schema(output: str, required_keys: list[str]) -> DeterministicResult:
    try:
        parsed = json.loads(output)
    except json.JSONDecodeError as e:
        return DeterministicResult("json_schema", False, f"Invalid JSON: {e}")
    missing = [k for k in required_keys if k not in parsed]
    if missing:
        return DeterministicResult("json_schema", False, f"Missing keys: {missing}")
    return DeterministicResult("json_schema", True)

def check_length(output: str, min_chars: int, max_chars: int) -> DeterministicResult:
    n = len(output)
    if n < min_chars:
        return DeterministicResult("length", False, f"{n} chars < min {min_chars}")
    if n > max_chars:
        return DeterministicResult("length", False, f"{n} chars > max {max_chars}")
    return DeterministicResult("length", True)

def check_no_pii(output: str) -> DeterministicResult:
    patterns = [
        (r'\b[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Z|a-z]{2,}\b', "email"),
        (r'\b\d{3}[\-\s]\d{2}[\-\s]\d{4}\b', "ssn"),
    ]
    for pat, name in patterns:
        if re.search(pat, output):
            return DeterministicResult("no_pii", False, f"Possible {name} found")
    return DeterministicResult("no_pii", True)

def run_t1_checks(output: str) -> list[DeterministicResult]:
    return [
        check_json_schema(output, ["summary", "action_items", "priority"]),
        check_length(output, min_chars=50, max_chars=2000),
        check_no_pii(output),
    ]

sample_output = '{{"summary": "Contract approved.", "action_items": [], "priority": "low"}}'
results = run_t1_checks(sample_output)
all_passed = all(r.passed for r in results)
print(f"T1 gate: {'PASS' if all_passed else 'FAIL'}")
for r in results:
    print(f"  {r.check}: {'✓' if r.passed else '✗'} {r.detail}")

import anthropic, json, statistics
from dataclasses import dataclass

@dataclass
class JudgeResult:
    case_id: str
    scores: dict[str, int]
    overall: float
    reasoning: str

def judge_response(case_id: str, judge_prompt: str,
                   model: str = "claude-sonnet-4-6") -> JudgeResult:
    client = anthropic.Anthropic()
    resp = client.messages.create(
        model=model,
        max_tokens=256,
        system=JUDGE_SYSTEM,
        messages=[{"role": "user", "content": judge_prompt}],
    )
    raw = resp.content[0].text.strip()
    data = json.loads(raw)
    scores = {k: v for k, v in data.items()
              if k not in ("overall", "reasoning")}
    return JudgeResult(case_id, scores, data["overall"], data["reasoning"])

def aggregate_judge_results(results: list[JudgeResult]) -> dict:
    overalls = [r.overall for r in results]
    return {
        "mean_overall": round(statistics.mean(overalls), 3),
        "min_overall":  round(min(overalls), 3),
        "pass_rate":    sum(1 for s in overalls if s >= 0.7) / len(overalls),
        "n": len(overalls),
    }
